sn_aia_tool.script:
(function(inputs) {
    var gr = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
    gr.initialize();
    gr.setValue('customer', inputs.customer);
    gr.setValue('device', inputs.device);
    gr.setValue('claim_reason', inputs.claim_reason);
    gr.setValue('state', '1');
    gr.setValue('priority', inputs.priority || '3');
    if (inputs.customer_name) gr.setValue('customer_name', inputs.customer_name);
    if (inputs.device_serial_number) gr.setValue('device_serial_number', inputs.device_serial_number);
    if (inputs.device_name) gr.setValue('device_name', inputs.device_name);

    // Auto-populate caller_name from current user
    var currentUser = gs.getUserDisplayName();
    gr.setValue('caller_name', currentUser || inputs.customer_name || 'Unknown');

    var sysId = gr.insert();
    if (!sysId) {
        return JSON.stringify({ status: 'error', message: 'Failed to create warranty claim record' });
    }

    // Read back to get the auto-generated number
    var created = new GlideRecord('x_snc_medwc_auto_0_warranty_claim');
    created.get(sysId);

    return JSON.stringify({
        status: 'success',
        message: 'Warranty claim created successfully',
        sys_id: sysId,
        number: created.getValue('number'),
        state: created.getValue('state'),
        priority: created.getValue('priority'),
        caller_name: created.getValue('caller_name')
    });
})(inputs);
